<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  return</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> errorResponse</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(req, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ERROR_CODES</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">USER_BAD_REQUEST_USER_NOT_FOUND</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
